{
  "questions": [
    {
      "question": "Where should I create the skills folder?",
      "options": [
        "In the project root as /skills/",
        "Alongside existing .claude/ config",
        "Let me specify a custom path",
        "Just package them as .skill files to download"
      ],
      "type": "single_select"
    },
    {
      "question": "What does your project structure look like?",
      "options": [
        "Monorepo (frontend + backend together)",
        "Separate repos (API + client)",
        "Single solution with multiple projects",
        "I'll share the structure"
      ],
      "type": "single_select"
    },
    {
      "question": "Which skills are highest priority? (rank them)",
      "options": [
        "Engineering (coding conventions, architecture)",
        "Codebase Index (file map for token savings)",
        "PM Review (PR/feature review checklist)",
        "Documentation (API docs, README, changelogs)"
      ],
      "type": "rank_priorities"
    }
  ]
}

{
  "questions": [
    {
      "question": "What kind of coding evaluation are we building?",
      "options": [
        "LeetCode-style (problems with test cases, pass/fail)",
        "Freeform sandbox (just run code, no grading)",
        "Both \u2014 problems with tests AND a free playground",
        "Assignment-based (instructor creates, students submit)"
      ],
      "type": "single_select"
    },
    {
      "question": "Which of these features should the schema support?",
      "options": [
        "User roles (admin, instructor, student)",
        "Teams / organizations",
        "Leaderboards / scoring",
        "Code execution history & replay"
      ],
      "type": "multi_select"
    },
    {
      "question": "How should test cases work?",
      "options": [
        "Simple I/O (input string \u2192 expected output string)",
        "Function-based (call function with args, check return value)",
        "Multi-step (setup \u2192 run \u2192 assert pattern)",
        "All of the above \u2014 flexible test runner"
      ],
      "type": "single_select"
    }
  ]
}
